-- DuckDB import helper generated by Phase 8 scripts.
CREATE OR REPLACE VIEW raw_results AS
SELECT * FROM read_json_auto('experiments/results/e6_weighted_fast/e6_weighted_fast_smoke_raw.jsonl');
CREATE OR REPLACE VIEW summary_results AS
SELECT * FROM read_csv_auto('experiments/results/e6_weighted_fast/e6_weighted_fast_smoke_summary.csv');
